{
  "type": "QUIZ",
  "lessonText": "Test your understanding of Python basics for game development.",
  "data": {
    "questions": [
      {
        "question": "What is the correct syntax to output 'Hello, World!' in Python?",
        "options": [
          "print('Hello, World!')",
          "echo 'Hello, World!'",
          "console.log('Hello, World!')",
          "write('Hello, World!')"
        ],
        "correctAnswer": 0,
        "explanation": "In Python, the print() function is used to output text."
      },
      {
        "question": "Which of the following is a valid variable name in Python?",
        "options": [
          "1st_variable",
          "_variable",
          "variable-name",
          "variable name"
        ],
        "correctAnswer": 1,
        "explanation": "Variable names in Python can start with a letter or underscore, but not a number."
      },
      {
        "question": "What data type is used to represent a sequence of characters in Python?",
        "options": [
          "String",
          "Integer",
          "Float",
          "Boolean"
        ],
        "correctAnswer": 0,
        "explanation": "Strings are used to represent text in Python."
      },
      {
        "question": "How do you start a comment in Python?",
        "options": [
          "// This is a comment",
          "# This is a comment",
          "/* This is a comment */",
          "<!-- This is a comment -->"
        ],
        "correctAnswer": 1,
        "explanation": "In Python, comments start with the '#' symbol."
      }
    ]
  }
}
